function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: [number, number, number][][] = new Array(n).fill(null).map(() => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push([v, start, end]);
    }

    // Initialize distance array
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;

    // Priority queue implemented as a min-heap
    const pq: [number, number][] = [];
    pq.push([0, 0]);

    // Helper functions for heap
    function push(value: [number, number]): void {
        pq.push(value);
        let i = pq.length - 1;
        while (i > 0) {
            const parent = Math.floor((i - 1) / 2);
            if (pq[parent][0] <= pq[i][0]) break;
            [pq[i], pq[parent]] = [pq[parent], pq[i]];
            i = parent;
        }
    }

    function pop(): [number, number] {
        if (pq.length === 0) return [Infinity, -1];
        const result = pq[0];
        pq[0] = pq[pq.length - 1];
        pq.pop();
        // Re-heapify
        let i = 0;
        while (true) {
            let left = 2 * i + 1;
            let right = 2 * i + 2;
            let smallest = i;
            if (left < pq.length && pq[left][0] < pq[smallest][0]) smallest = left;
            if (right < pq.length && pq[right][0] < pq[smallest][0]) smallest = right;
            if (smallest === i) break;
            [pq[i], pq[smallest]] = [pq[smallest], pq[i]];
            i = smallest;
        }
        return result;
    }

    while (pq.length > 0) {
        const [time, u] = pop();
        if (u === n - 1) return time;
        if (time > dist[u]) continue;

        for (const [v, start, end] of adj[u]) {
            const s = Math.max(time, start);
            if (s <= end) {
                const newTime = s + 1;
                if (newTime < dist[v]) {
                    dist[v] = newTime;
                    push([newTime, v]);
                }
            }
        }
    }

    return -1;
}

